import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const serviceTypes = [
  'Full House Move',
  'Office Relocation',
  'Single Item Delivery',
  'Packing Service',
];

const propertyTypes = ['Apartment', 'Townhouse', 'Detached House', 'Office', 'Storage'];

const initialState = {
  serviceType: serviceTypes[0],
  propertyType: propertyTypes[0],
  pickupAddress: '',
  destinationAddress: '',
  date: '',
  time: '',
  remarks: '',
};

const UserCreateBookingForm = ({ bookings, setBookings, editingBooking, setEditingBooking }) => {
  const { user } = useAuth();
  const [formData, setFormData] = useState(initialState);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (editingBooking) {
      setFormData({
        serviceType: editingBooking.serviceType,
        propertyType: editingBooking.propertyType,
        pickupAddress: editingBooking.pickupAddress,
        destinationAddress: editingBooking.destinationAddress,
        date: editingBooking.date?.slice(0, 10) || '',
        time: editingBooking.time || '',
        remarks: editingBooking.remarks || '',
      });
    } else {
      setFormData(initialState);
    }
  }, [editingBooking]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!user) return;
    setSubmitting(true);

    try {
      if (editingBooking) {
        const response = await axiosInstance.put(`/api/bookings/${editingBooking._id}`, formData, {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        setBookings(bookings.map((booking) => (booking._id === response.data._id ? response.data : booking)));
      } else {
        const response = await axiosInstance.post('/api/bookings', formData, {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        setBookings([...bookings, response.data]);
      }
      setEditingBooking(null);
      setFormData(initialState);
    } catch (error) {
      alert('Failed to save booking. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  const handleCancel = () => {
    setEditingBooking(null);
    setFormData(initialState);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-5">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
        <select
          name="serviceType"
          value={formData.serviceType}
          onChange={handleChange}
          className="w-full rounded-xl bg-[#C1D8F0] drop-shadow-lg py-3 px-6 text-[#0d2440] focus:outline-none focus:ring-2 focus:ring-[#6aa7ff]"
        >
          {serviceTypes.map((option) => (
            <option key={option} value={option}>
              {option}
            </option>
          ))}
        </select>
        <select
          name="propertyType"
          value={formData.propertyType}
          onChange={handleChange}
          className="w-full rounded-xl bg-[#C1D8F0] drop-shadow-lg py-3 px-6 text-[#0d2440] focus:outline-none focus:ring-2 focus:ring-[#6aa7ff]"
        >
          {propertyTypes.map((option) => (
            <option key={option} value={option}>
              {option}
            </option>
          ))}
        </select>
        <input
          type="text"
          name="pickupAddress"
          placeholder="Pick Up Address"
          value={formData.pickupAddress}
          onChange={handleChange}
          className="w-full rounded-xl bg-[#C1D8F0] drop-shadow-lg py-3 px-6 text-black md:col-span-2"
          required
        />
        <input
          type="text"
          name="destinationAddress"
          placeholder="Destination Address"
          value={formData.destinationAddress}
          onChange={handleChange}
          className="w-full rounded-xl bg-[#C1D8F0] drop-shadow-lg py-3 px-6 text-black md:col-span-2"
          required
        />
        <input
          type="date"
          name="date"
          value={formData.date}
          onChange={handleChange}
          className="w-full rounded-xl bg-[#C1D8F0] drop-shadow-lg py-3 px-6 text-black"
          required
        />
        <input
          type="time"
          name="time"
          value={formData.time}
          onChange={handleChange}
          className="w-full rounded-xl bg-[#C1D8F0] drop-shadow-lg py-3 px-6 text-black"
          required
        />
        <textarea
          name="remarks"
          placeholder="Remark (Optional)"
          value={formData.remarks}
          onChange={handleChange}
          className="w-full rounded-xl bg-[#C1D8F0] drop-shadow-lg py-3 px-6 text-black md:col-span-2"
          rows={3}
        />
      </div>
      <p className="text-center text-[#864C69] text-sm">
        *We will send a confirmation email to your registered email address.
      </p>
      <div className="flex flex-wrap justify-center gap-4">
        <button
          type="submit"
          className="w-48 rounded-full bg-[#C1D8F0] text-black font-semibold py-3 hover:bg-[#93A9C0] transition drop-shadow-lg"
          disabled={submitting}
        >
          {submitting ? 'Saving...' : editingBooking ? 'Update Booking' : 'Submit'}
        </button>
        {editingBooking && (
          <button
            type="button"
            onClick={handleCancel}
            className="w-48 rounded-full bg-white text-[#0d2440] font-semibold py-3 border border-[#0d2440]/30 hover:bg-[#f1f5f9] transition"
          >
            Cancel
          </button>
        )}
      </div>
    </form>
  );
};

export default UserCreateBookingForm;
